import React, { useEffect, useState } from "react";
import axios from "axios";
import Table from "../Components/Table";

const Booking = () => {
  const [bookings, setBookings] = useState([]);
  const [form, setForm] = useState({
    PhongSo: "",
    MaKH: "",
    NgayDat: "",
    NgayNhan: "",
    NgayTra: "",
    SoNguoi: "",
    TinhTrang: "dadat",
  });
  const [search, setSearch] = useState({
    PhongSo: "",
    MaKH: "",
  });
  const [editMode, setEditMode] = useState(false);

  const apiBase = "http://localhost:5000/api/booking";

  const fetchBookings = async () => {
    try {
      const params = Object.fromEntries(Object.entries(search).filter(([_, v]) => v));
      const res = await axios.get(`${apiBase}/allbooking`, { params });
      const sorted = res.data.sort((a, b) => Number(a.PhongSo) - Number(b.PhongSo));
      setBookings(sorted);
    } catch (err) {
      alert("Lỗi khi tải danh sách booking");
    }
  };

  useEffect(() => {
    fetchBookings();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editMode) {
        await axios.put(`${apiBase}/updatebooking`, form);
        alert("Cập nhật booking thành công");
      } else {
        await axios.post(`${apiBase}/addbooking`, form);
        alert("Thêm booking thành công");
      }
      setForm({
        PhongSo: "",
        MaKH: "",
        NgayDat: "",
        NgayNhan: "",
        NgayTra: "",
        SoNguoi: "",
        TinhTrang: "dadat",
      });
      setEditMode(false);
      fetchBookings();
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const handleDelete = async (PhongSo, NgayDat) => {
    if (!window.confirm("Bạn có chắc muốn hủy booking này?")) return;
    try {
      await axios.delete(`${apiBase}/deletebooking`, { data: { PhongSo, NgayDat } });
      fetchBookings();
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const handleEdit = (b) => {
    setForm(b);
    setEditMode(true);
  };

  // Table columns
  const columns = [
    { key: "PhongSo", label: "Phòng số" },
    { key: "MaKH", label: "Mã KH" },
    { key: "NgayDat", label: "Ngày đặt" },
    { key: "NgayNhan", label: "Ngày nhận" },
    { key: "NgayTra", label: "Ngày trả" },
    { key: "SoNguoi", label: "Số người" },
    { key: "TinhTrang", label: "Tình trạng" },
    { key: "actions", label: "Hành động" },
  ];

  const tableData = bookings.map((b) => ({
    ...b,
    actions: (
      <div className="flex justify-center items-center space-x-1">
        <button
          onClick={() => handleEdit(b)}
          className="bg-yellow-400 hover:bg-yellow-500 text-white px-3 py-1 rounded-l shadow flex items-center gap-1"
        >
          ✏️ Sửa
        </button>
        <button
          onClick={() => handleDelete(b.PhongSo, b.NgayDat)}
          className="bg-red-500 hover:bg-red-600 text-white px-3 py-1 rounded-r shadow flex items-center gap-1"
        >
          🗑 Hủy
        </button>
      </div>
    ),
  }));

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4 text-blue-600">📅 Quản lý đặt phòng</h1>

      {/* Form thêm/sửa booking */}
      <form className="mb-4 space-y-2" onSubmit={handleSubmit}>
        {["PhongSo", "MaKH", "NgayDat", "NgayNhan", "NgayTra", "SoNguoi"].map((key) => (
          <input
            key={key}
            type={key.includes("Ngay") ? "date" : "text"}
            placeholder={key}
            name={key}
            value={form[key]}
            onChange={(e) => setForm({ ...form, [key]: e.target.value })}
            className="border p-2 w-full rounded"
            disabled={editMode && key === "PhongSo"}
          />
        ))}
        <select
          name="TinhTrang"
          value={form.TinhTrang}
          onChange={(e) => setForm({ ...form, TinhTrang: e.target.value })}
          className="border p-2 w-full rounded"
        >
          <option value="trong">🟢 Trống</option>
          <option value="dadat">🔴 Đã đặt</option>
        </select>
        <button
          type="submit"
          className={`px-4 py-2 rounded text-white shadow flex items-center gap-2 ${
            editMode ? "bg-green-500 hover:bg-green-600" : "bg-blue-500 hover:bg-blue-600"
          }`}
        >
          {editMode ? "💾 Cập nhật" : "➕ Thêm booking"}
        </button>
      </form>

      {/* Tìm kiếm */}
      <div className="mb-4 space-y-2">
        <h2 className="font-semibold">🔍 Tìm kiếm booking</h2>
        <div className="flex items-center space-x-2">
          <input
            placeholder="Phòng số"
            value={search.PhongSo}
            onChange={(e) => setSearch({ ...search, PhongSo: e.target.value })}
            className="border p-2 rounded flex-1"
          />
          <input
            placeholder="Mã KH"
            value={search.MaKH}
            onChange={(e) => setSearch({ ...search, MaKH: e.target.value })}
            className="border p-2 rounded flex-1"
          />
          <button
            onClick={fetchBookings}
            className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded shadow flex items-center gap-1"
          >
            🔎 Tìm kiếm
          </button>
        </div>
      </div>

      {/* Table */}
      <Table columns={columns} data={tableData} />
    </div>
  );
};

export default Booking;
